const FRONTEND_CHUNK_3 = "\n    globalUnpaidUids.add(uid);\r\n    let startStr = document.getElementById('fin-payroll-start').value;\r\n    let endStr = document.getElementById('fin-payroll-end').value;\r\n    enrichShiftsWithMath(startStr, endStr);\r\n    \r\n    if (currentPayrollView !== 'person') {\r\n        currentPayrollView = 'person';\r\n        document.getElementById('fin-tab-person').className = 'btn-main';\r\n        document.getElementById('fin-tab-event').className = 'btn-outline';\r\n        document.getElementById('fin-payroll-view-person').style.display = 'block';\r\n        document.getElementById('fin-payroll-view-event').style.display = 'none';\r\n    }\r\n    \r\n    let safePerson = uid.replace(/[^a-zA-Z0-9]/g, '-');\r\n    finToggleState['person-' + safePerson] = 'block';\r\n    \r\n    renderPayrollByPerson();\r\n}\r\n\r\n\r\n// @INDEX: FINANCIALS -> Settings & Overheads\r\nfunction loadFinSettingsUI() {\r\n    document.getElementById('fin-subtab-labor').style.opacity = '0.5';\r\n    google.script.run.withSuccessHandler(res => {\r\n        renderFinRolesUI(res.roles || {});\r\n        finOverheadsList = res.overheads || [];\r\n        renderFinOverheadsUI();\r\n        \r\n        let t = res.trucks || {};\r\n        const setV = (id, val) => { \r\n            let el = document.getElementById(id); \r\n            if (el) el.value = (val !== undefined && typeof val !== 'object') ? val : ''; \r\n        };\r\n        setV('fin-set-truck-t1-in', t.truck_t1_in); setV('fin-set-truck-t1-out', t.truck_t1_out); setV('fin-set-truck-t1-stay', t.truck_t1_stay);\r\n        setV('fin-set-truck-t2-in', t.truck_t2_in); setV('fin-set-truck-t2-out', t.truck_t2_out); setV('fin-set-truck-t2-stay', t.truck_t2_stay);\r\n        setV('fin-set-truck-t3-in', t.truck_t3_in); setV('fin-set-truck-t3-out', t.truck_t3_out); setV('fin-set-truck-t3-stay', t.truck_t3_stay);\r\n        setV('fin-set-truck-t4-in', t.truck_t4_in); setV('fin-set-truck-t4-out', t.truck_t4_out); setV('fin-set-truck-t4-stay', t.truck_t4_stay);\r\n\r\n        let g = res.globals || {};\r\n        setV('fin-set-prep-rate', g.prep_rate); setV('fin-set-prep-hours', g.prep_hours);\r\n        setV('fin-set-recovery-rate', g.recovery_rate); setV('fin-set-recovery-hours', g.recovery_hours);\r\n        setV('fin-set-build-rate', g.build_rate); setV('fin-set-build-hours', g.build_hours);\r\n        setV('fin-set-duty-rate', g.duty_rate); setV('fin-set-duty-hours', g.duty_hours);\r\n        setV('fin-set-break-rate', g.break_rate); setV('fin-set-break-hours', g.break_hours);\r\n        setV('fin-set-default-shift-period', g.default_shift_period);\r\n        setV('fin-set-overtime-multiplier', g.overtime_multiplier);\r\n        setV('fin-set-followspot-bonus', g.followspot_bonus);\r\n        setV('fin-set-console-bonus', g.console_bonus);\r\n        setV('fin-set-extra-rate-standard', g.extra_rate_standard !== undefined ? g.extra_rate_standard : 15);\r\n        setV('fin-set-extra-rate-prep', g.extra_rate_prep !== undefined ? g.extra_rate_prep : 15);\r\n\r\n        document.getElementById('fin-subtab-labor').style.opacity = '1';\r\n    }).getFinancialSettings();\r\n}\r\n\r\nfunction switchFinSubTab(tab) {\r\n    document.getElementById('fin-subtab-labor').style.display = 'none';\r\n    document.getElementById('fin-subtab-overheads').style.display = 'none';\r\n    \r\n    ['labor', 'overheads'].forEach(function(t) {\r\n        var btn = document.getElementById('fin-subtab-btn-' + t);\r\n        if (btn) btn.classList.toggle('active', t === tab);\r\n    });\r\n    \r\n    document.getElementById('fin-subtab-' + tab).style.display = 'flex';\r\n}\r\n\r\nfunction renderFinRolesUI(savedRoles) {\r\n    let html = '';\r\n    if (typeof ROLE_COLORS !== 'undefined') {\r\n        Object.keys(ROLE_COLORS).sort().forEach(role => {\r\n                let saved = savedRoles[role] || { mult: 1.0 };\r\n            let bgCol = ROLE_COLORS[role].bg || '#86efac';\r\n            html += `\r\n            <div class=\"fin-role-row\" data-role=\"${role.replace(/\"/g, '&quot;')}\" style=\"display:flex; flex-wrap:wrap; gap:10px; background:#222; padding:12px; border-radius:6px; border:1px solid #333; align-items:center;\">\r\n                <div style=\"flex:1; min-width:120px; display:flex; align-items:center; gap:8px;\">\r\n                    <span style=\"color:${bgCol}; font-weight:bold; font-size:13px;\">${role}</span>\r\n                </div>\r\n                    <div style=\"width:80px;\">\r\n                        <div class=\"input-label\" style=\"font-size:9px;\">Multiplier</div>\r\n                        <input type=\"number\" step=\"0.1\" class=\"role-mult\" value=\"${saved.mult !== undefined ? saved.mult : 1.0}\" style=\"padding:6px; width:100%; box-sizing:border-box;\" title=\"Role Multiplier\">\r\n                </div>\r\n            </div>`;\r\n        });\r\n    }\r\n    document.getElementById('fin-roles-container').innerHTML = html;\r\n}\r\n\r\nfunction addFinOverheadRow() {\r\n    finOverheadsList.push({ name: '', amount: 0, frequency: 'Monthly' });\r\n    renderFinOverheadsUI();\r\n}\r\n\r\nfunction renderFinOverheadsUI() {\r\n    let html = '';\r\n    finOverheadsList.forEach((item, idx) => {\r\n        html += `\r\n        <div style=\"display:flex; gap:10px; background:#222; padding:12px; border-radius:6px; border:1px solid #333; align-items:center;\">\r\n            <div style=\"flex:2;\">\r\n                <div class=\"input-label\" style=\"font-size:9px;\">Expense Name</div>\r\n                <input type=\"text\" value=\"${item.name.replace(/\"/g, '&quot;')}\" oninput=\"finOverheadsList[${idx}].name = this.value\" placeholder=\"e.g. Warehouse Rent\" style=\"padding:6px; width:100%; box-sizing:border-box;\">\r\n            </div>\r\n            <div style=\"flex:1;\">\r\n                <div class=\"input-label\" style=\"font-size:9px;\">Amount (€)</div>\r\n                <input type=\"number\" step=\"0.01\" value=\"${item.amount}\" oninput=\"finOverheadsList[${idx}].amount = parseFloat(this.value)||0\" style=\"padding:6px; width:100%; box-sizing:border-box;\">\r\n            </div>\r\n            <div style=\"flex:1;\">\r\n                <div class=\"input-label\" style=\"font-size:9px;\">Frequency</div>\r\n                <select onchange=\"finOverheadsList[${idx}].frequency = this.value\" style=\"padding:6px; width:100%; box-sizing:border-box; border-radius:4px; background:#111; color:#fff; border:1px solid #444; height:32px;\">\r\n                    <option value=\"Monthly\" ${item.frequency === 'Monthly' ? 'selected' : ''}>Monthly</option>\r\n                    <option value=\"Yearly\" ${item.frequency === 'Yearly' ? 'selected' : ''}>Yearly</option>\r\n                </select>\r\n            </div>\r\n            <button class=\"btn-delete\" style=\"margin-top:14px; padding:6px 12px !important;\" onclick=\"finOverheadsList.splice(${idx}, 1); renderFinOverheadsUI();\">X</button>\r\n        </div>`;\r\n    });\r\n    if(html === '') html = '<div style=\"color:#888; font-size:12px; font-style:italic; text-align:center; padding:20px;\">No overheads added.</div>';\r\n    document.getElementById('fin-overheads-container').innerHTML = html;\r\n}\r\n\r\nfunction handleSaveFinancialSettings() {\r\n    let btn = event.currentTarget;\r\n    let orig = btn.innerText;\r\n    btn.innerText = \"SAVING...\"; btn.disabled = true;\r\n\r\n    let roles = {};\r\n    document.querySelectorAll('.fin-role-row').forEach(row => {\r\n        let role = row.dataset.role;\r\n        roles[role] = {\r\n            mult: parseFloat(row.querySelector('.role-mult').value) || 1.0\r\n        };\r\n    });\r\n\r\n    const getVal = (id, def = 0) => {\r\n        let el = document.getElementById(id);\r\n        if(!el) return def;\r\n        let v = parseFloat(el.value);\r\n        return isNaN(v) ? def : v;\r\n    };\r\n\r\n    let trucks = {\r\n        truck_t1_in: getVal('fin-set-truck-t1-in'), truck_t1_out: getVal('fin-set-truck-t1-out'), truck_t1_stay: getVal('fin-set-truck-t1-stay'),\r\n        truck_t2_in: getVal('fin-set-truck-t2-in'), truck_t2_out: getVal('fin-set-truck-t2-out'), truck_t2_stay: getVal('fin-set-truck-t2-stay'),\r\n        truck_t3_in: getVal('fin-set-truck-t3-in'), truck_t3_out: getVal('fin-set-truck-t3-out'), truck_t3_stay: getVal('fin-set-truck-t3-stay'),\r\n        truck_t4_in: getVal('fin-set-truck-t4-in'), truck_t4_out: getVal('fin-set-truck-t4-out'), truck_t4_stay: getVal('fin-set-truck-t4-stay')\r\n    };\r\n    \r\n    let globals = {\r\n        prep_rate: getVal('fin-set-prep-rate', 80),\r\n        prep_hours: getVal('fin-set-prep-hours', 8),\r\n        recovery_rate: getVal('fin-set-recovery-rate', 80),\r\n        recovery_hours: getVal('fin-set-recovery-hours', 8),\r\n        build_rate: getVal('fin-set-build-rate', 100),\r\n        build_hours: getVal('fin-set-build-hours', 6),\r\n        duty_rate: getVal('fin-set-duty-rate', 120),\r\n        duty_hours: getVal('fin-set-duty-hours', 8),\r\n        break_rate: getVal('fin-set-break-rate', 80),\r\n        break_hours: getVal('fin-set-break-hours', 4),\r\n        default_shift_period: getVal('fin-set-default-shift-period', 12),\r\n        overtime_multiplier: getVal('fin-set-overtime-multiplier', 1.5),\r\n        followspot_bonus: getVal('fin-set-followspot-bonus', 0),\r\n        console_bonus: getVal('fin-set-console-bonus', 0),\r\n        extra_rate_standard: getVal('fin-set-extra-rate-standard', 15),\r\n        extra_rate_prep: getVal('fin-set-extra-rate-prep', 15)\r\n    };\r\n\r\n    let payload = {\r\n        roles: roles,\r\n        overheads: finOverheadsList,\r\n        trucks: trucks,\r\n        globals: globals\r\n    };\r\n\r\n    google.script.run\r\n        .withSuccessHandler(() => {\r\n            btn.innerText = \"SAVED ✓\";\r\n            setTimeout(() => { btn.innerText = orig; btn.disabled = false; }, 2000);\r\n        })\r\n        .withFailureHandler(err => {\r\n            alert(\"Error saving settings: \" + err.message);\r\n            btn.innerText = orig; btn.disabled = false;\r\n        })\r\n        .saveFinancialSettings(payload);\r\n}\r\n\n\n";
